import{_ as e,r as o,o as c,c as l,b as s,e as t,w as p,d as n,f as i}from"./app-55c326ac.js";const u={},r=s("h1",{id:"python-linux的shell命令",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#python-linux的shell命令","aria-hidden":"true"},"#"),n(" Python: Linux的Shell命令")],-1),d={class:"table-of-contents"},k=i(`<p><strong>前言</strong> 有时候难免需要直接调用Shell命令来完成一些比较简单的操作，比如mount一个文件系统之类的。那么我们使用Python如何调用Linux的Shell命令？</p><h2 id="_1-os模块" tabindex="-1"><a class="header-anchor" href="#_1-os模块" aria-hidden="true">#</a> 1.os模块</h2><h3 id="_1-1-os模块的exec方法" tabindex="-1"><a class="header-anchor" href="#_1-1-os模块的exec方法" aria-hidden="true">#</a> 1.1 os模块的exec方法</h3><p>Python的exec系统方法同Unix的exec系统调用是一致的。这些方法适用于在子进程中调用外部程序的情况，因为外部程序会替换当前进程的代码，不会返回</p><h3 id="_1-2-os模块的system方法" tabindex="-1"><a class="header-anchor" href="#_1-2-os模块的system方法" aria-hidden="true">#</a> 1.2 os模块的system方法</h3><p>system方法会创建子进程运行外部程序，此方法只返回外部程序的运行结果（相当于shell命令的直接结果 <code>$?</code>）。这个方法适用于外部程序没有输出结果的情况</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> os
os<span class="token punctuation">.</span>system<span class="token punctuation">(</span><span class="token string">&quot;echo \\&quot;Hello World\\&quot;&quot;</span><span class="token punctuation">)</span> <span class="token comment">#直接调用os.system调用一个echo命令，返回值为0或者大于0的数</span>

val <span class="token operator">=</span> os<span class="token punctuation">.</span>system<span class="token punctuation">(</span><span class="token string">&quot;ls -al | grep \\&quot;log\\&quot;&quot;</span><span class="token punctuation">)</span>  <span class="token comment"># 使用val接收返回值</span>
<span class="token keyword">print</span> val <span class="token comment"># 命令正常运行时，返回值为0</span>

val <span class="token operator">=</span> os<span class="token punctuation">.</span>syset<span class="token punctuation">(</span><span class="token string">&quot;ls -al | grep \\&quot;log1\\&quot;&quot;</span>）
<span class="token keyword">print</span><span class="token punctuation">(</span>val<span class="token punctuation">)</span>   <span class="token comment"># 使用OS.system调用一个没有返回结果的命令，返回值为256.</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上面的方法只返回外部程序的结果，就是<code>os.system</code>的结果。想接收命令的返回值，可使用下面的方法</p><h3 id="_1-3-os模块的popen方法" tabindex="-1"><a class="header-anchor" href="#_1-3-os模块的popen方法" aria-hidden="true">#</a> 1.3 os模块的popen方法</h3><p>当需要得到外部程序的输出结果时，可使用<code>os.popen</code>方法。如使用urllib调用Web API时，需要对得到的数据进行处理。<br><code>os.popen(cmd)</code>要得到命令的输出结果，只需要在调用下<code>read()</code>或者<code>readlines()</code>即可</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> os
val <span class="token operator">=</span> os<span class="token punctuation">.</span>popen<span class="token punctuation">(</span><span class="token string">&#39;ls -lt&#39;</span><span class="token punctuation">)</span>  <span class="token comment"># 调用os.popen(cmd)并不能直观的得到我们想要的结果，需要进一步使用read或者readlines来只管得到我们的结果</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>val<span class="token punctuation">.</span>read<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>    <span class="token comment"># 调用read()方法得到命令的输出结果</span>

vall <span class="token operator">=</span> os<span class="token punctuation">.</span>popen<span class="token punctuation">(</span><span class="token string">&#39;ls -lt&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span>read<span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># 将命令的输出结果复制给变量vall</span>
<span class="token keyword">for</span> i <span class="token keyword">in</span> vall<span class="token punctuation">:</span>
 <span class="token keyword">print</span> <span class="token punctuation">(</span>i<span class="token punctuation">)</span>      <span class="token comment"># 输出每行的结果</span>
 <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>i<span class="token punctuation">)</span>     <span class="token comment"># 查看i的类型</span>
 <span class="token builtin">str</span> <span class="token operator">=</span> <span class="token builtin">str</span><span class="token punctuation">(</span>i<span class="token punctuation">,</span>encoding<span class="token operator">=</span><span class="token string">&#39;utf8&#39;</span><span class="token punctuation">)</span> <span class="token comment"># 对i的进行类型变换</span>
 <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span><span class="token builtin">str</span><span class="token punctuation">)</span><span class="token punctuation">)</span>    <span class="token comment"># 查看str的类型</span>
 <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">str</span><span class="token punctuation">)</span>      <span class="token comment"># 输出str</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_2-commands模块" tabindex="-1"><a class="header-anchor" href="#_2-commands模块" aria-hidden="true">#</a> 2.commands模块</h2><p>使用 <code>commands.getoutput方法</code><br> 通os.popen()的区别在于popen返回的是一个文件句柄，也就是byter字节类型。<br> 而 commands.getoutput方法将外部程序的输出结果当做字符串返回。<br> 主要方法:</p><ul><li>commands.getstatusoutput(cmd) 返回（status,output）</li><li>commands.getoutput(cmd) 只返回输出结果</li><li>commands.getstatus(cmd) 返回cmd的执行结果的字符串</li></ul><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">import</span> commands
abc <span class="token operator">=</span> commands<span class="token punctuation">.</span>getstatusoutput<span class="token punctuation">(</span><span class="token string">&#39;ls -lt&#39;</span><span class="token punctuation">)</span>  <span class="token comment"># 返回（status,output）</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token builtin">type</span><span class="token punctuation">(</span>abc<span class="token punctuation">)</span><span class="token punctuation">)</span>
commands<span class="token punctuation">.</span>getoutput<span class="token punctuation">(</span><span class="token string">&#39;ls -lt&#39;</span><span class="token punctuation">)</span>   <span class="token comment"># 返回命令的输出结果</span>
command<span class="token punctuation">.</span>getstatus<span class="token punctuation">(</span><span class="token string">&#39;ls -lt&#39;</span><span class="token punctuation">)</span>    <span class="token comment"># 调用commands.getoutput中的命令对&#39;log&#39;文件进行相同的操作</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-subprocess模块" tabindex="-1"><a class="header-anchor" href="#_3-subprocess模块" aria-hidden="true">#</a> 3.subprocess模块</h2><p>Python官方说明，subprocess模块用于取代上面这些模块。有一个用Python实现的并行ssh工具—mssh，代码很简短，不过很有意思，它在线程中调用subprocess启动子进程来干活。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">from</span> subprocess <span class="token keyword">import</span> call
call<span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&quot;ls&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;-l&quot;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>

r <span class="token operator">=</span> subprocess<span class="token punctuation">.</span>call<span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token string">&#39;nslookup&#39;</span><span class="token punctuation">,</span><span class="token string">&#39;www.python.org&#39;</span><span class="token punctuation">]</span><span class="token punctuation">)</span>  <span class="token comment">#此时还是会在屏幕输出执行结果</span>
<span class="token keyword">print</span><span class="token punctuation">(</span>r<span class="token punctuation">)</span>   <span class="token comment"># 输出命令的返回值（类似于Linux中Shell命令的 $? ）</span>

<span class="token comment"># 案例2</span>
<span class="token comment"># 使用subprocess.Popen()执行命令并持续获取返回值</span>
<span class="token comment"># 方法1：</span>
<span class="token keyword">import</span> subprocess
order<span class="token operator">=</span><span class="token string">&#39;tailf /var/log/access.log&#39;</span> <span class="token comment">#查看日志信息</span>
pi<span class="token operator">=</span> subprocess<span class="token punctuation">.</span>Popen<span class="token punctuation">(</span>order<span class="token punctuation">,</span>shell<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span>stdout<span class="token operator">=</span>subprocess<span class="token punctuation">.</span>PIPE<span class="token punctuation">)</span>
<span class="token keyword">print</span> pi<span class="token punctuation">.</span>stdout<span class="token punctuation">.</span>read<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token comment">#打印结果</span>
<span class="token comment"># 此结果是一次性返回，但当需要持续输出日志信息的时候，结果会不断打印出日志信息，如果还是使用read()，等待时间就比较漫长。可以使用下面的方法</span>
<span class="token comment"># 方法2</span>
<span class="token keyword">import</span> subprocess
order <span class="token operator">=</span> <span class="token string">&#39;tailf /var/log/access.log&#39;</span>
pi <span class="token operator">=</span> subprocess<span class="token punctuation">.</span>Popen<span class="token punctuation">(</span>order<span class="token punctuation">,</span>shell<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span>stdout<span class="token operator">=</span>subprocess<span class="token punctuation">.</span>PIPE<span class="token punctuation">)</span>
<span class="token keyword">for</span> i <span class="token keyword">in</span> pi<span class="token punctuation">.</span>stdout<span class="token punctuation">.</span>readlines<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
 <span class="token keyword">print</span> <span class="token punctuation">(</span>i<span class="token punctuation">)</span>
 
<span class="token comment"># 当需要将ping等类似命令，并且存在实时输出显示在屏幕可以是用下面的方法</span>
<span class="token keyword">import</span> subprocess
order <span class="token operator">=</span> <span class="token string">&#39;/root/paping ipaddress -p ipport&#39;</span>
pi <span class="token operator">=</span> subprocess<span class="token punctuation">.</span>Popen<span class="token punctuation">(</span>order<span class="token punctuation">,</span>shell<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">,</span>stdout<span class="token operator">=</span>subprocess<span class="token punctuation">.</span>PIPE<span class="token punctuation">)</span>
<span class="token keyword">for</span> i <span class="token keyword">in</span> <span class="token punctuation">(</span>pi<span class="token punctuation">.</span>stdout<span class="token punctuation">.</span>readline<span class="token punctuation">,</span><span class="token string">&#39;b&#39;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
 <span class="token keyword">print</span> <span class="token punctuation">(</span>i<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>subprocess与system相比的优势是它更灵活（你可以得到标准输出，标准错误，“真正”的状态代码，更好的错误处理，等..）。</p>`,19);function m(v,b){const a=o("router-link");return c(),l("div",null,[r,s("nav",d,[s("ul",null,[s("li",null,[t(a,{to:"#_1-os模块"},{default:p(()=>[n("1.os模块")]),_:1}),s("ul",null,[s("li",null,[t(a,{to:"#_1-1-os模块的exec方法"},{default:p(()=>[n("1.1 os模块的exec方法")]),_:1})]),s("li",null,[t(a,{to:"#_1-2-os模块的system方法"},{default:p(()=>[n("1.2 os模块的system方法")]),_:1})]),s("li",null,[t(a,{to:"#_1-3-os模块的popen方法"},{default:p(()=>[n("1.3 os模块的popen方法")]),_:1})])])]),s("li",null,[t(a,{to:"#_2-commands模块"},{default:p(()=>[n("2.commands模块")]),_:1})]),s("li",null,[t(a,{to:"#_3-subprocess模块"},{default:p(()=>[n("3.subprocess模块")]),_:1})])])]),k])}const y=e(u,[["render",m],["__file","Python-Linux的Shell命令.html.vue"]]);export{y as default};
